extern crate rand;
use rand::{Rng, thread_rng};
use std::fmt::Write;
use std::error::Error;

fn generate_token() -> Result<String, Box<dyn Error>> {
    let mut rng = thread_rng();
    let chars: Vec<char> = (b'a'..=b'z')
        .chain(b'A'..=b'Z')
        .chain(b'0'..=b'9')
        .take(64)
        .collect();
    let mut token = String::with_capacity(40);
    for _ in 0..40 {
        token.push(chars[rng.gen_range(0..chars.len())]);
    }
    Ok(token)
}